"/* Custom Fonts and Core Variables */
:root {
  --neon-cyan: #00f0ff;
  --neon-purple: #bd00ff;
  --neon-pink: #ff0055;
  --neon-green: #00ff66;
  --neon-yellow: #ffcc00;

  --bg-dark: #020208;
  --bg-glass: rgba(6, 10, 24, 0.65);
  --border-glass: rgba(0, 240, 255, 0.2);
  --border-glass-hover: rgba(0, 240, 255, 0.45);

  --font-title: 'Orbitron', sans-serif;
  --font-mono: 'Share Tech Mono', monospace;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  user-select: none;
}

body, html {
  width: 100%;
  height: 100%;
  overflow: hidden;
  background-color: var(--bg-dark);
  color: #e2e8f0;
  font-family: var(--font-mono);
  font-size: 14px;
}

/* 3D Scene Viewport */
#canvas-container {
  position: absolute;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  z-index: 1;
}

/* HUD Overlay Styling */
#hud {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: 10;
  pointer-events: none; /* Let pointer pass to canvas */
  display: grid;
  grid-template-columns: 280px 1fr 300px;
  grid-template-rows: 60px 1fr 100px;
  grid-template-areas:
    "top top top"
    "left center right"
    "bottom bottom bottom";
  padding: 15px;
  gap: 15px;
}

/* Make sure inner panels capture clicks */
.hud-panel {
  pointer-events: auto;
  position: relative;
  display: flex;
  flex-direction: column;
}

/* Glassmorphism Panel Base */
.glass {
  background: var(--bg-glass);
  backdrop-filter: blur(12px) saturate(160%);
  -webkit-backdrop-filter: blur(12px) saturate(160%);
  border: 1px solid var(--border-glass);
  border-radius: 8px;
  box-shadow: 
    0 4px 30px rgba(0, 0, 0, 0.4),
    inset 0 0 15px rgba(0, 240, 255, 0.03);
  overflow: hidden;
  transition: border-color 0.3s ease, box-shadow 0.3s ease;
}

.glass:hover {
  border-color: var(--border-glass-hover);
